  ('social-worker-moex-02245', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問依據我國的家庭暴力防治法，關於聲請保護令的相關規定，下列敘述何者錯誤？', '["家暴被害人得向法院聲請緊急保護令", "當被害人為未成年人或身心障礙者時，法定代理人或三親等以內的血親或姻親，得為其向法院聲請通 常保護令", "法院核發暫時保護令或緊急保護令，得不經審理程序", "法院於受理緊急保護令之聲請後，依聲請人到庭或電話陳述家庭暴力之事實，足認被害人有受家庭暴 力之急迫危險者，應於四小時內以書面核發緊急保護令"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02246', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依性別工作平等法育嬰留職停薪的相關規定，下列敘述何者錯誤？', '["受僱者於任職滿六個月後，於每一子女滿三歲前，得申請育嬰留職停薪", "受僱者於育嬰留職停薪期間，得繼續參加原有之社會保險，原由雇主負擔之保險費，免予繳納；原由 受僱者負擔之保險費，得遞延三年繳納", "受僱者的育嬰留職停薪津貼發放，依勞工保險條例的相關規定給付", "受僱者同時撫育子女二人以上者，其育嬰留職停薪期間應合併計算，最長以最幼子女受撫育二年為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
