  ('social-worker-moex-02249', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據我國的家庭暴力防治法，家庭暴力是指家庭成員間實施身體、精神或經濟上之騷擾、控制、脅迫或 其他不法侵害之行為，而該法所指的家庭成員，不包括下列何者？', '["前配偶", "同居的未婚男女朋友", "現為或曾為五親等以內之旁系血親或旁系姻親", "同居共組家庭的同志伴侶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
